import{c as t,Q as a,j as r,m as i}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"GPT-5.5 System Card","description":"","frontmatter":{"title":"GPT-5.5 System Card","authors":"OpenAI","published":"2026-04-23T00:00:00.000Z","source":"https://deploymentsafety.openai.com/gpt-5-5"},"headers":[],"relativePath":"research/papers/2026-04-23-gpt5-5-system-card.md","filePath":"research/papers/2026-04-23-gpt5-5-system-card.md","lastUpdated":1779894392000}'),n={name:"research/papers/2026-04-23-gpt5-5-system-card.md"};function o(s,e,l,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="gpt-5-5-system-card" tabindex="-1">GPT-5.5 System Card <a class="header-anchor" href="#gpt-5-5-system-card" aria-label="Permalink to &quot;GPT-5.5 System Card&quot;">​</a></h1><p><strong>Authors</strong>: OpenAI <strong>Published</strong>: April 23, 2026 (updated April 24, 2026 with API safeguard details) <strong>Source</strong>: <a href="https://deploymentsafety.openai.com/gpt-5-5" target="_blank" rel="noreferrer">https://deploymentsafety.openai.com/gpt-5-5</a><strong>PDF</strong>: <a href="https://deploymentsafety.openai.com/gpt-5-5/gpt-5-5.pdf" target="_blank" rel="noreferrer">https://deploymentsafety.openai.com/gpt-5-5/gpt-5-5.pdf</a><strong>Announcement</strong>: <a href="https://openai.com/index/introducing-gpt-5-5/" target="_blank" rel="noreferrer">https://openai.com/index/introducing-gpt-5-5/</a></p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>GPT-5.5 is OpenAI&#39;s model designed for <strong>complex, real-world workflows</strong>: code writing, web research, multi-step document and spreadsheet creation, and tool-enabled tasks. Priced higher than GPT-5.4 but 40% more token-efficient, resulting in ~20% higher operational cost overall. Achieves state-of-the-art on Terminal-Bench Hard, GDPval-AA, and APEX-Agents-AA.</p><hr><h2 id="model-variants" tabindex="-1">Model Variants <a class="header-anchor" href="#model-variants" aria-label="Permalink to &quot;Model Variants&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variant</th><th>Notes</th></tr></thead><tbody><tr><td>GPT-5.5</td><td>Standard API model</td></tr><tr><td>GPT-5.5 Pro</td><td>Same underlying model + enhanced parallel test-time compute</td></tr></tbody></table><hr><h2 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th>Input</th><th>Output</th><th>vs GPT-5.4</th></tr></thead><tbody><tr><td>GPT-5.5</td><td>$5 / 1M</td><td>$30 / 1M</td><td>2× cost per token</td></tr><tr><td>Effective cost (with efficiency)</td><td>~20% higher overall</td><td></td><td>-40% tokens used</td></tr></tbody></table><p><strong>Cost-performance tradeoffs</strong> (from Artificial Analysis benchmarks):</p><ul><li>GPT-5.5 (medium effort) ≈ Claude Opus 4.7 performance at ~¼ the cost</li><li>GPT-5.5 (low effort) ≈ comparable performance at ~½ the cost</li></ul><hr><h2 id="benchmark-results" tabindex="-1">Benchmark Results <a class="header-anchor" href="#benchmark-results" aria-label="Permalink to &quot;Benchmark Results&quot;">​</a></h2><h3 id="agent-and-reasoning-benchmarks" tabindex="-1">Agent and Reasoning Benchmarks <a class="header-anchor" href="#agent-and-reasoning-benchmarks" aria-label="Permalink to &quot;Agent and Reasoning Benchmarks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>GPT-5.5</th><th>Notes</th></tr></thead><tbody><tr><td>Terminal-Bench Hard</td><td><strong>SoTA</strong></td><td>Best-in-class</td></tr><tr><td>GDPval-AA</td><td><strong>1785 Elo</strong></td><td>Leading by significant margin</td></tr><tr><td>APEX-Agents-AA</td><td><strong>SoTA</strong></td><td>Best-in-class</td></tr><tr><td>AA-Omniscience</td><td><strong>57%</strong></td><td>Highest factual accuracy</td></tr><tr><td>SWE-bench Pro</td><td><strong>58.6%</strong></td><td>Single-pass, end-to-end</td></tr></tbody></table><h3 id="coding-benchmark" tabindex="-1">Coding Benchmark <a class="header-anchor" href="#coding-benchmark" aria-label="Permalink to &quot;Coding Benchmark&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>Score</th><th>Notes</th></tr></thead><tbody><tr><td>SWE-bench Pro</td><td>58.6%</td><td>End-to-end single pass</td></tr></tbody></table><p><em>For comparison: Claude Opus 4.7: 64.3% on SWE-bench Pro</em></p><h3 id="health" tabindex="-1">Health <a class="header-anchor" href="#health" aria-label="Permalink to &quot;Health&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>Score</th><th>Delta</th></tr></thead><tbody><tr><td>HealthBench length-adjusted</td><td>56.5</td><td>+2.5 pts vs predecessor</td></tr><tr><td>HealthBench Professional</td><td>51.8%</td><td>+3.7 pts</td></tr></tbody></table><h3 id="hallucination" tabindex="-1">Hallucination <a class="header-anchor" href="#hallucination" aria-label="Permalink to &quot;Hallucination&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Hallucination Rate</th></tr></thead><tbody><tr><td>GPT-5.5</td><td><strong>86%</strong> (high — individual claims correct rate: +23%)</td></tr><tr><td>Claude Opus 4.7 (max)</td><td>36%</td></tr></tbody></table><p><strong>Note</strong>: Despite 23% improvement in individual claim factual accuracy, the overall hallucination rate of 86% is substantially higher than Claude Opus 4.7. Artificial Analysis notes the model &quot;may provide confident answers even without reliable knowledge.&quot;</p><hr><h2 id="safety-evaluation" tabindex="-1">Safety Evaluation <a class="header-anchor" href="#safety-evaluation" aria-label="Permalink to &quot;Safety Evaluation&quot;">​</a></h2><h3 id="disallowed-content" tabindex="-1">Disallowed Content <a class="header-anchor" href="#disallowed-content" aria-label="Permalink to &quot;Disallowed Content&quot;">​</a></h3><ul><li>Performance &quot;on par with GPT-5.4-Thinking&quot; across challenging prompts</li><li>Category regressions statistically insignificant</li></ul><h3 id="robustness" tabindex="-1">Robustness <a class="header-anchor" href="#robustness" aria-label="Permalink to &quot;Robustness&quot;">​</a></h3><ul><li>Jailbreak evaluations: defender success rates comparable to predecessors</li><li>Prompt injection resistance robust across connector-based attacks</li></ul><h3 id="cybersecurity-high-capability-sub-critical" tabindex="-1">Cybersecurity (High Capability, Sub-Critical) <a class="header-anchor" href="#cybersecurity-high-capability-sub-critical" aria-label="Permalink to &quot;Cybersecurity (High Capability, Sub-Critical)&quot;">​</a></h3><ul><li>Measurable improvements in vulnerability identification and exploitation tasks</li><li>Cannot independently produce functional full-chain exploits against hardened real-world systems</li><li>Cyber range: <strong>93.33% pass rate</strong> (up from 73.33% for GPT-5.4-Thinking)</li></ul><h3 id="biological-chemical-high-capability" tabindex="-1">Biological/Chemical (High Capability) <a class="header-anchor" href="#biological-chemical-high-capability" aria-label="Permalink to &quot;Biological/Chemical (High Capability)&quot;">​</a></h3><ul><li>Hard-negative protein binding prediction below concerning thresholds</li><li>DNA sequence design significantly underperforms baseline methods</li></ul><h3 id="ai-self-improvement" tabindex="-1">AI Self-Improvement <a class="header-anchor" href="#ai-self-improvement" aria-label="Permalink to &quot;AI Self-Improvement&quot;">​</a></h3><ul><li>Does not meet High capability thresholds</li><li>Falls short of mid-career research engineer performance levels</li></ul><hr><h2 id="key-safety-findings" tabindex="-1">Key Safety Findings <a class="header-anchor" href="#key-safety-findings" aria-label="Permalink to &quot;Key Safety Findings&quot;">​</a></h2><h3 id="cot-controllability" tabindex="-1">CoT Controllability <a class="header-anchor" href="#cot-controllability" aria-label="Permalink to &quot;CoT Controllability&quot;">​</a></h3><p>Lower ability to reshape reasoning traces compared to predecessors — <strong>suggests improved monitoring reliability</strong> (reasoning is more stable and predictable).</p><h3 id="red-teaming" tabindex="-1">Red Teaming <a class="header-anchor" href="#red-teaming" aria-label="Permalink to &quot;Red Teaming&quot;">​</a></h3><p>~200 early-access partners provided feedback; public jailbreak bounty program used for universal jailbreak research.</p><hr><h2 id="safeguards" tabindex="-1">Safeguards <a class="header-anchor" href="#safeguards" aria-label="Permalink to &quot;Safeguards&quot;">​</a></h2><ul><li>Model safety training + conversation monitoring + actor-level enforcement</li><li>Expanded safeguards for biological and cybersecurity domains</li><li>Trusted access program for defenders (less restricted model variants)</li></ul><hr><h2 id="third-party-assessment" tabindex="-1">Third-Party Assessment <a class="header-anchor" href="#third-party-assessment" aria-label="Permalink to &quot;Third-Party Assessment&quot;">​</a></h2><p>From Artificial Analysis (April 2026):</p><ul><li>GPT-5.5 <strong>leads the Intelligence Index</strong>, ending a three-way tie among OpenAI, Anthropic, and Google</li><li>Dominates Terminal-Bench Hard, GDPval-AA, APEX-Agents-AA</li><li>Leads 5 of 8 key evaluations; 2nd place on the remaining 3</li></ul><p>From Zvi (independent reviewer):</p><ul><li>&quot;Solid improvement&quot;; performs competitively with Claude Opus 4.7 on straightforward tasks</li><li>Claude may excel on open-ended interpretation work</li><li>System card &quot;provides less detail than Anthropic&#39;s Mythos and Opus model cards&quot;</li></ul><hr><h2 id="transparency-note" tabindex="-1">Transparency Note <a class="header-anchor" href="#transparency-note" aria-label="Permalink to &quot;Transparency Note&quot;">​</a></h2><p>The GPT-5.5 system card is notably shorter than Anthropic&#39;s system cards. Several reviewers noted reduced transparency compared to Claude system cards regarding alignment issues.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>GPT-5.5 is the primary OpenAI competitor reference for May 2026:</p><ol><li><strong>Benchmark calibration</strong>: GPT-5.5 leads on Terminal-Bench Hard and GDPval-AA; Claude Opus 4.7 leads on SWE-bench Pro (64.3% vs 58.6%)</li><li><strong>Hallucination gap</strong>: GPT-5.5 at 86% vs Claude Opus 4.7 at 36% — significant reliability difference for factual tasks in <code>research-hub</code> and <code>autoresearch</code></li><li><strong>Cost-efficiency</strong>: GPT-5.5 (medium) ≈ Opus 4.7 at ¼ the cost — relevant for <code>finops</code> when choosing provider</li><li><strong>Terminal-Bench SoTA</strong>: GPT-5.5 is the current best agent on Terminal-Bench Hard, above Claude Code + Opus 4.5 (58% in the Terminal-Bench paper from January 2026)</li><li><strong>CoT stability</strong>: Lower CoT controllability = more predictable reasoning chains — favorable for monitoring in <code>harness-meta</code> observability design</li></ol>',59)])])}const m=t(n,[["render",o]]);export{u as __pageData,m as default};
